type EventCallback = (data: any) => void;

class DerivService {
  private socket: WebSocket | null = null;
  private listeners: Map<string, EventCallback[]> = new Map();
  private mockMode: boolean = false;
  private mockInterval: any = null;
  private autoTradeInterval: any = null;
  private balance: number = 0;
  private isTrading: boolean = false;
  private currentStrategy: any = null;
  private lastDigit: number = 0;
  private currentPrice: number = 0;
  private stake: number = 0.35;
  private realAccountBalance: number = 0;
  private realCurrency: string = 'USD';

  connect(token: string, isMock: boolean = true): Promise<void> {
    this.mockMode = isMock;
    this.balance = isMock ? 10000 : 0;
    
    if (this.mockMode) {
      console.log('đźŽ® Mock Mode Active - Starting demo trading');
      this.startMockData();
      return Promise.resolve();
    }

    return new Promise((resolve, reject) => {
      try {
        console.log('đź”Ś Connecting to Deriv REAL API...');
        this.socket = new WebSocket('wss://ws.derivws.com/websockets/v3?app_id=1089');
        
        this.socket.onopen = () => {
          console.log('WebSocket open, authorizing...');
          this.socket?.send(JSON.stringify({ authorize: token }));
        };

        this.socket.onmessage = (event) => {
          const data = JSON.parse(event.data);
          
          if (data.msg_type === 'authorize') {
            console.log('âś… Authorized! Balance:', data.authorize.balance);
            this.realAccountBalance = data.authorize.balance;
            this.realCurrency = data.authorize.currency;
            this.balance = data.authorize.balance;
            this.emit('connected', { balance: this.balance, currency: this.realCurrency });
            resolve();
          }
          
          if (data.msg_type === 'tick') {
            this.currentPrice = data.tick.quote;
            this.lastDigit = Math.floor(this.currentPrice) % 10;
            this.emit('tick', { price: this.currentPrice, digit: this.lastDigit });
          }
          
          if (data.msg_type === 'buy') {
            console.log('Trade placed:', data);
            this.emit('trade_placed', data);
          }
          
          if (data.msg_type === 'proposal_open_contract') {
            if (data.proposal_open_contract.is_sold) {
              const profit = data.proposal_open_contract.profit;
              this.balance += profit;
              this.realAccountBalance = this.balance;
              this.emit('trade', {
                id: data.proposal_open_contract.contract_id,
                type: data.proposal_open_contract.contract_type,
                stake: data.proposal_open_contract.buy_price,
                profit: profit,
                win: profit > 0,
                timestamp: new Date()
              });
              this.emit('balance', { balance: this.balance });
            }
          }
          
          if (data.msg_type === 'error') {
            console.error('Deriv API Error:', data.error);
            this.emit('error', data.error);
          }
        };
        
        this.socket.onerror = (error) => {
          console.error('WebSocket error:', error);
          reject(error);
        };
      } catch (error) {
        console.error('Connection error:', error);
        reject(error);
      }
    });
  }

  private startMockData() {
    let price = 1234.56;
    
    this.emit('connected', { balance: this.balance });
    
    this.mockInterval = setInterval(() => {
      price += (Math.random() - 0.5) * 3;
      this.currentPrice = price;
      this.lastDigit = Math.floor(price) % 10;
      this.emit('tick', { price, digit: this.lastDigit });
      
      const time = Math.floor(Date.now() / 60000) * 60000;
      const candle = {
        time,
        open: price - (Math.random() * 2),
        high: price + (Math.random() * 3),
        low: price - (Math.random() * 3),
        close: price,
        volume: Math.floor(Math.random() * 1000) + 500
      };
      this.emit('candle', { candle });
    }, 1000);
  }

  startAutoTrading(strategy: any, stakeAmount: number) {
    this.isTrading = true;
    this.currentStrategy = strategy;
    this.stake = stakeAmount;
    
    console.log('đźš€ Auto Trading Started with strategy:', strategy?.name);
    
    this.autoTradeInterval = setInterval(() => {
      if (!this.isTrading) return;
      
      if (this.mockMode) {
        const winRate = strategy?.winRate || 70;
        const isWin = Math.random() * 100 < winRate;
        const profit = isWin ? this.stake * 0.9 : -this.stake;
        
        this.balance += profit;
        
        const trade = {
          id: Math.random().toString(36).substr(2, 9),
          type: strategy?.name || 'KXNG Strategy',
          stake: this.stake,
          profit: profit,
          win: isWin,
          timestamp: new Date()
        };
        
        console.log('Trade placed:', trade);
        this.emit('trade', trade);
        this.emit('balance', { balance: this.balance });
      }
    }, 2000);
  }

  stopAutoTrading() {
    this.isTrading = false;
    if (this.autoTradeInterval) {
      clearInterval(this.autoTradeInterval);
      this.autoTradeInterval = null;
    }
    console.log('đź›‘ Auto Trading Stopped');
  }

  resetStats() {
    console.log('Stats reset');
    this.emit('stats_reset', {});
  }

  placeTrade(contract: any) {
    console.log('Placing manual trade:', contract);
    
    if (this.mockMode) {
      setTimeout(() => {
        const win = Math.random() > 0.45;
        const profit = win ? contract.amount * 0.9 : -contract.amount;
        this.balance += profit;
        
        this.emit('trade', {
          id: Math.random().toString(36).substr(2, 9),
          type: contract.contract_type,
          stake: contract.amount,
          profit: profit,
          win: win,
          timestamp: new Date()
        });
        this.emit('balance', { balance: this.balance });
      }, 2000);
      return;
    }
    this.socket?.send(JSON.stringify(contract));
  }

  on(event: string, callback: EventCallback) {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event)?.push(callback);
  }

  private emit(event: string, data: any) {
    this.listeners.get(event)?.forEach(cb => {
      try { cb(data); } catch (e) { console.error(e); }
    });
  }

  disconnect() {
    this.stopAutoTrading();
    if (this.mockInterval) clearInterval(this.mockInterval);
    if (this.autoTradeInterval) clearInterval(this.autoTradeInterval);
    this.socket?.close();
  }
}

export default DerivService;
